/*!
 * SplitText Shim v1.0
 * Replaces Club GSAP SplitText with a free alternative.
 * Provides the same API as GSAP's SplitText.
 */
(function(window) {
    "use strict";

    function SplitText(target, config) {
        config = config || {};
        this.elements = [];
        this.chars = [];
        this.words = [];
        this.lines = [];

        // Resolve target
        var targets;
        if (typeof target === "string") {
            targets = Array.prototype.slice.call(document.querySelectorAll(target));
        } else if (target && target.nodeType) {
            targets = [target];
        } else if (target && target.length) {
            targets = Array.prototype.slice.call(target);
        } else {
            targets = [];
        }

        this.elements = targets;
        this._originals = [];
        this._config = config;

        var types = (config.type || config.types || "chars,words,lines").split(",").map(function(s) { return s.trim(); });
        var self = this;

        targets.forEach(function(el) {
            self._originals.push(el.innerHTML);
            self._splitElement(el, types);
        });
    }

    SplitText.prototype._splitElement = function(el, types) {
        var self = this;
        var linesClass = this._config.linesClass || "split-line";
        var wordsClass = this._config.wordsClass || "split-word";
        var charsClass = this._config.charsClass || "split-char";

        var doChars = types.indexOf("chars") !== -1;
        var doWords = types.indexOf("words") !== -1;
        var doLines = types.indexOf("lines") !== -1;

        // Get plain text
        var originalText = el.innerText || el.textContent;

        el.innerHTML = "";
        el.style.overflow = "hidden";

        if (doLines) {
            // Split into lines using a measuring approach
            var words = originalText.split(/\s+/).filter(function(w) { return w.length > 0; });
            var testSpan = document.createElement("span");
            testSpan.style.visibility = "hidden";
            testSpan.style.position = "absolute";
            el.appendChild(testSpan);

            var lines = [];
            var currentLine = [];
            var lastTop = -1;

            // Build word spans first
            var wordSpans = words.map(function(word) {
                var span = document.createElement("span");
                span.textContent = word + " ";
                span.style.display = "inline-block";
                el.appendChild(span);
                return span;
            });

            // Wait a tick, then measure lines
            // (We do it synchronously here with getBoundingClientRect)
            wordSpans.forEach(function(span) {
                var top = span.getBoundingClientRect().top;
                if (lastTop === -1) lastTop = top;
                if (top !== lastTop) {
                    lines.push(currentLine.slice());
                    currentLine = [];
                    lastTop = top;
                }
                currentLine.push(span);
            });
            if (currentLine.length) lines.push(currentLine);

            // Remove word spans
            wordSpans.forEach(function(s) { el.removeChild(s); });
            el.removeChild(testSpan);
            el.style.overflow = "";

            // Rebuild with line wrappers
            lines.forEach(function(lineWords) {
                var lineEl = document.createElement("div");
                lineEl.className = linesClass;
                lineEl.style.display = "block";
                lineEl.style.overflow = "hidden";

                lineWords.forEach(function(w) {
                    var wordEl;
                    if (doChars) {
                        wordEl = document.createElement("span");
                        wordEl.className = wordsClass;
                        wordEl.style.display = "inline-block";
                        w.textContent.trim().split("").forEach(function(ch) {
                            var charEl = document.createElement("span");
                            charEl.className = charsClass;
                            charEl.style.display = "inline-block";
                            charEl.textContent = ch;
                            wordEl.appendChild(charEl);
                            self.chars.push(charEl);
                        });
                        // Space after word
                        wordEl.appendChild(document.createTextNode(" "));
                    } else if (doWords) {
                        wordEl = document.createElement("span");
                        wordEl.className = wordsClass;
                        wordEl.style.display = "inline-block";
                        wordEl.textContent = w.textContent;
                        self.words.push(wordEl);
                    } else {
                        wordEl = document.createTextNode(w.textContent);
                    }
                    lineEl.appendChild(wordEl);
                });

                el.appendChild(lineEl);
                self.lines.push(lineEl);
            });

        } else if (doWords || doChars) {
            var words2 = originalText.split(/(\s+)/);
            words2.forEach(function(word) {
                if (/^\s+$/.test(word)) {
                    el.appendChild(document.createTextNode(word));
                    return;
                }
                if (doChars) {
                    var wordWrap = document.createElement("span");
                    wordWrap.className = wordsClass;
                    wordWrap.style.display = "inline-block";
                    word.split("").forEach(function(ch) {
                        var charEl = document.createElement("span");
                        charEl.className = charsClass;
                        charEl.style.display = "inline-block";
                        charEl.textContent = ch;
                        wordWrap.appendChild(charEl);
                        self.chars.push(charEl);
                    });
                    el.appendChild(wordWrap);
                    self.words.push(wordWrap);
                } else {
                    var wordEl2 = document.createElement("span");
                    wordEl2.className = wordsClass;
                    wordEl2.style.display = "inline-block";
                    wordEl2.textContent = word;
                    el.appendChild(wordEl2);
                    self.words.push(wordEl2);
                }
            });
        }
    };

    SplitText.prototype.split = function(config) {
        // Re-split with new config (no-op in this shim, already split)
        return this;
    };

    SplitText.prototype.revert = function() {
        var self = this;
        this.elements.forEach(function(el, i) {
            if (self._originals[i] !== undefined) {
                el.innerHTML = self._originals[i];
            }
        });
        this.chars = [];
        this.words = [];
        this.lines = [];
        return this;
    };

    // Register with GSAP
    if (window.gsap) {
        gsap.registerPlugin({
            name: "SplitText",
            register: function() {}
        });
    }

    window.SplitText = SplitText;

})(window);
